/* ═══════════════════════════════════════════════════════════
   CONSTANTS & COORDINATE HELPERS
═══════════════════════════════════════════════════════════ */
const SKY_R   = 800;          // radius of sky sphere
const LAT_DEG = 21.0;         // Hawaiʻi latitude
const LAT_RAD = LAT_DEG * Math.PI / 180;
const DEG     = Math.PI / 180;

/* RA/Dec → XYZ on unit sphere (equatorial) */
function raDecToXYZ(ra, dec, radius) {
  const phi = dec * DEG;
  const lam = ra  * DEG;
  const r   = radius || SKY_R;
  return new THREE.Vector3(
    r * Math.cos(phi) * Math.cos(lam),
    r * Math.sin(phi),
    r * Math.cos(phi) * Math.sin(lam)
  );
}

/* Apparent Julian Day from JS Date */
function getJD(date) { return date.getTime() / 86400000 + 2440587.5; }

/* Local Sidereal Time (degrees) at Hawaiʻi longitude -157.8° */

/* ══════════════════════════════════════════════════════════
   OBSERVER LOCATION — live GPS with Hawaiʻi fallback
══════════════════════════════════════════════════════════ */
const OBSERVER = {
  lat:  21.31,   // degrees N  (Hawaiʻi default)
  lon: -157.82,  // degrees E  (Hawaiʻi default)
  name: "Hawaiʻi (default)",
  geoGranted: false,
};

function initGeolocation() {
  if (!navigator.geolocation) return;
  navigator.geolocation.getCurrentPosition(
    pos => {
      OBSERVER.lat        = pos.coords.latitude;
      OBSERVER.lon        = pos.coords.longitude;
      OBSERVER.geoGranted = true;
      // Reverse-geocode display name via free API
      fetch(`https://nominatim.openstreetmap.org/reverse?lat=${OBSERVER.lat}&lon=${OBSERVER.lon}&format=json`)
        .then(r => r.json())
        .then(d => {
          OBSERVER.name = d.address?.city || d.address?.town || d.address?.county || d.display_name?.split(',')[0] || 'Your Location';
          _updateLocationDisplay();
        }).catch(() => { OBSERVER.name = `${OBSERVER.lat.toFixed(2)}°N`; _updateLocationDisplay(); });
      _updateLocationDisplay();
      console.log('[IKE] Location acquired:', OBSERVER.lat.toFixed(4), OBSERVER.lon.toFixed(4));
    },
    err => {
      console.log('[IKE] Geolocation denied, using Hawaiʻi default');
      OBSERVER.name = "Hawaiʻi 21°N";
      _updateLocationDisplay();
    },
    { enableHighAccuracy: false, timeout: 8000 }
  );
}

function _updateLocationDisplay() {
  const el = document.getElementById('observer-location');
  if (el) el.textContent = OBSERVER.name;
  // Update topbar subtitle
  const tt = document.getElementById('top-title');
  if (tt) tt.textContent = `Ka Pānalāʻā Hōkū · ${OBSERVER.name} ${Math.abs(OBSERVER.lat).toFixed(1)}°${OBSERVER.lat>=0?'N':'S'}`;
  // Rebuild LST with real longitude
}

/* LST now uses real observer longitude */
function getLST(date) {
  const JD  = getJD(date || new Date());
  const T   = (JD - 2451545.0) / 36525;
  const GST = (280.46061837 + 360.98564736629*(JD-2451545) + 0.000387933*T*T) % 360;
  return ((GST + OBSERVER.lon + 360) % 360);  // real longitude, not hardcoded Hawaiʻi
}



/* Build rotation matrix from equatorial to horizontal at Hawaiʻi */
function getSkySpin(lst) { return lst; /* degrees to rotate sky */ }

/* Star colour from B-V index (approximate) */
function bvToColor(mag) {
  if (mag < -0.2) return new THREE.Color(0.7, 0.8, 1.0);   // blue-white
  if (mag <  0.5) return new THREE.Color(0.95, 0.95, 1.0); // white
  if (mag <  1.0) return new THREE.Color(1.0, 0.97, 0.88); // yellow-white
  if (mag <  1.5) return new THREE.Color(1.0, 0.9, 0.7);   // yellow
  return new THREE.Color(1.0, 0.75, 0.55);                  // orange-red
}

