/* ── Cached DOM refs (never query in hot path) ── */
let _dom = {};
function _cacheDOM() {
  ['time-display','date-display','tp-label','tp-slider','nav-house','nav-deg',
   'compass-look-dir','compass-canvas','cursor'].forEach(id => {
    _dom[id] = document.getElementById(id);
  });
}

/* ── Performance: dirty flag + frame skip for slow updates ── */
let _frameCount = 0;
let _lastLST = -999;
