/* Planet orbital mechanics — Keplerian elements */
function planetPosition(planet, T) {
  const D = T * 36525;
  const r2d = 180/Math.PI;
  const L = ((planet.L0 + planet.Ldot*D) % 360 + 360) % 360;
  const w = planet.wbar + (planet.wbarDot||0)*D;
  const e = planet.e, a = planet.a;
  const I = planet.I * DEG, Om = ((planet.Om + (planet.OmDot||0)*D) * DEG + Math.PI*4) % (Math.PI*2);
  let M = ((L - w)*DEG % (Math.PI*2) + Math.PI*2) % (Math.PI*2);
  let E = M; for(let i=0;i<5;i++) E = M + e*Math.sin(E);
  const nu = 2*Math.atan2(Math.sqrt(1+e)*Math.sin(E/2), Math.sqrt(1-e)*Math.cos(E/2));
  const r  = a*(1-e*Math.cos(E));
  const wRad = w*DEG;
  const x = r*(Math.cos(Om)*Math.cos(nu+wRad-Om)-Math.sin(Om)*Math.sin(nu+wRad-Om)*Math.cos(I));
  const y = r*(Math.sin(Om)*Math.cos(nu+wRad-Om)+Math.cos(Om)*Math.sin(nu+wRad-Om)*Math.cos(I));
  const z = r*Math.sin(nu+wRad-Om)*Math.sin(I);
  const Le = (100.464+0.9856474*D)*DEG;
  const dx=x+Math.cos(Le), dy=y+Math.sin(Le), dz=z;
  const eps=23.44*DEG;
  const yeq=dy*Math.cos(eps)-dz*Math.sin(eps), zeq=dy*Math.sin(eps)+dz*Math.cos(eps);
  const ra  = ((Math.atan2(yeq,dx)/DEG)+360)%360;
  const dec = Math.asin(Math.max(-1,Math.min(1,zeq/Math.sqrt(dx*dx+dy*dy+dz*dz))))/DEG;
  return {ra, dec};
}

