/* ── Planet texture generator ── */
function makeSaturnRingTexture(size=1024) {
  const canvas=document.createElement('canvas'); canvas.width=size; canvas.height=64;
  const ctx=canvas.getContext('2d');
  const grad=ctx.createLinearGradient(0,0,size,0);
  grad.addColorStop(0.00,'rgba(0,0,0,0)'); grad.addColorStop(0.10,'rgba(160,140,110,0.65)');
  grad.addColorStop(0.22,'rgba(220,205,170,0.82)'); grad.addColorStop(0.36,'rgba(170,150,118,0.74)');
  grad.addColorStop(0.50,'rgba(125,110,86,0.20)'); grad.addColorStop(0.62,'rgba(210,195,160,0.78)');
  grad.addColorStop(0.84,'rgba(150,130,102,0.62)'); grad.addColorStop(1.00,'rgba(0,0,0,0)');
  ctx.fillStyle=grad; ctx.fillRect(0,0,size,64);
  for(let i=0;i<180;i++){ctx.fillStyle=`rgba(255,255,255,${0.01+Math.random()*0.03})`;ctx.fillRect(Math.random()*size,0,1+Math.random()*3,64);}
  const tex=new THREE.CanvasTexture(canvas); tex.needsUpdate=true; return tex;
}

function makeAtmosphereMaterial(hexColor,power=2.4,opacity=0.55) {
  return new THREE.ShaderMaterial({
    uniforms:{glowColor:{value:new THREE.Color(hexColor)},c:{value:0.3},p:{value:power},opacity:{value:opacity}},
    vertexShader:`varying float vIntensity;uniform float c;uniform float p;
      void main(){vec3 vNormal=normalize(normalMatrix*normal);vec3 vNormel=normalize(normalMatrix*vec3(0,0,1));
      vIntensity=pow(c-dot(vNormal,vNormel),p);gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1);}`,
    fragmentShader:`uniform vec3 glowColor;uniform float opacity;varying float vIntensity;
      void main(){gl_FragColor=vec4(glowColor*vIntensity,vIntensity*opacity);}`,
    side:THREE.BackSide,blending:THREE.AdditiveBlending,transparent:true,depthWrite:false
  });
}

function makePlanetTexture(planet,size=1024) {
  const canvas=document.createElement('canvas'); canvas.width=canvas.height=size;
  const ctx=canvas.getContext('2d');
  const base=new THREE.Color(planet.color||'#cccccc');
  ctx.fillStyle=`rgb(${Math.round(base.r*255)},${Math.round(base.g*255)},${Math.round(base.b*255)})`;
  ctx.fillRect(0,0,size,size);
  const band=(y,h,col,a=0.25)=>{ctx.save();ctx.globalAlpha=a;ctx.fillStyle=col;ctx.fillRect(0,y,size,h);ctx.restore();};
  switch(planet.id){
    case 'mercury':
      for(let i=0;i<120;i++){ctx.fillStyle=`rgba(90,80,70,${0.04+Math.random()*0.06})`;ctx.beginPath();ctx.arc(Math.random()*size,Math.random()*size,4+Math.random()*24,0,Math.PI*2);ctx.fill();}
      break;
    case 'venus':
      for(let i=0;i<12;i++) band(i*size/12,size/18,'rgba(255,255,255,0.16)',0.32);
      ctx.fillStyle='rgba(255,250,235,0.18)'; ctx.fillRect(0,0,size,size); break;
    case 'mars':
      band(size*0.18,size*0.10,'rgba(120,60,35,0.24)',0.35);
      band(size*0.52,size*0.12,'rgba(145,80,45,0.28)',0.32);
      for(let i=0;i<80;i++){ctx.fillStyle=`rgba(90,45,25,${0.06+Math.random()*0.08})`;ctx.beginPath();ctx.arc(Math.random()*size,Math.random()*size,5+Math.random()*16,0,Math.PI*2);ctx.fill();}
      break;
    case 'jupiter':
      for(let i=0;i<18;i++){const y=i*size/18;band(y,size/18,i%3===0?'rgba(181,122,75,1)':i%3===1?'rgba(230,198,148,1)':'rgba(204,152,108,1)',0.14+(i%2)*0.07);}
      ctx.fillStyle='rgba(196,100,72,0.32)';ctx.beginPath();ctx.ellipse(size*0.70,size*0.58,size*0.10,size*0.06,-0.2,0,Math.PI*2);ctx.fill();break;
    case 'saturn':
      for(let i=0;i<16;i++) band(i*size/16,size/16,i%2?'rgba(188,156,108,1)':'rgba(214,188,142,1)',0.16+(i%4===0?0.08:0));break;
    case 'uranus': band(size*0.38,size*0.08,'rgba(255,255,255,0.08)',0.24);band(size*0.62,size*0.06,'rgba(210,255,255,0.09)',0.2);break;
    case 'neptune': band(size*0.24,size*0.07,'rgba(120,170,255,0.18)',0.3);band(size*0.53,size*0.10,'rgba(60,100,205,0.20)',0.28);break;
  }
  const ov=ctx.createRadialGradient(size*0.35,size*0.32,size*0.04,size*0.5,size*0.5,size*0.65);
  ov.addColorStop(0,'rgba(255,255,255,0.18)');ov.addColorStop(0.55,'rgba(255,255,255,0.03)');ov.addColorStop(1,'rgba(0,0,0,0.14)');
  ctx.fillStyle=ov;ctx.fillRect(0,0,size,size);
  const tex=new THREE.CanvasTexture(canvas);tex.needsUpdate=true;return tex;
}

function buildPlanets() {
  const saturnRingTex = makeSaturnRingTexture();
  PLANETS.forEach(planet => {
    const r = planet.size;
    const geo = new THREE.SphereGeometry(r, 48, 48);
    const tex = makePlanetTexture(planet);
    const bumpScales = {mercury:0.55,venus:0.04,mars:0.28,jupiter:0.03,saturn:0.02,uranus:0.01,neptune:0.01};
    const roughness   = {venus:0.92,mercury:0.98,mars:0.92,jupiter:0.84,saturn:0.86,uranus:0.78,neptune:0.76};
    const spinRates   = {mercury:0.0005,venus:-0.00018,mars:0.00065,jupiter:0.0014,saturn:0.0012,uranus:-0.0009,neptune:0.0010};
    const axialTilts  = {mercury:0.001,venus:Math.PI,mars:0.44,jupiter:0.05,saturn:0.47,uranus:1.71,neptune:0.49};
    const mat = new THREE.MeshPhysicalMaterial({
      map:tex, bumpMap:tex, bumpScale:bumpScales[planet.id]||0.04,
      color:new THREE.Color(planet.color), roughness:roughness[planet.id]||0.82, metalness:0.0,
      clearcoat:planet.id==='venus'?0.12:0.04, clearcoatRoughness:0.72,
      emissive:new THREE.Color(planet.id==='venus'?0x11110b:0x000000),
      emissiveIntensity:planet.id==='venus'?0.28:0.0
    });
    const mesh = new THREE.Mesh(geo, mat);
    mesh.userData = { isPlanet:true, planet, spinRate:spinRates[planet.id]||0.0005 };
    mesh.rotation.z = axialTilts[planet.id]||0;
    scene.add(mesh);

    // Saturn rings
    let ring = null;
    if (planet.id==='saturn') {
      const ringGeo = new THREE.RingGeometry(r*1.46, r*2.5, 128, 4);
      /* Fix RingGeometry UVs so texture maps radially (not the default which is angular) */
      const _rpos = ringGeo.attributes.position;
      const _ruv  = ringGeo.attributes.uv;
      const _rIn = r*1.46, _rOut = r*2.5;
      for (let ri = 0; ri < _rpos.count; ri++) {
        const rx = _rpos.getX(ri), ry = _rpos.getY(ri);
        const rd = Math.sqrt(rx*rx + ry*ry);
        _ruv.setXY(ri, (rd - _rIn) / (_rOut - _rIn), 0.5);
      }
      _ruv.needsUpdate = true;
      const ringMat = new THREE.MeshBasicMaterial({
        map:saturnRingTex, color:0xf0e0c0, transparent:true, opacity:0.88,
        side:THREE.DoubleSide, depthWrite:false
      });
      ring = new THREE.Mesh(ringGeo, ringMat);
      ring.rotation.x = Math.PI * 0.46;
      ring.rotation.z = 0.1;
      mesh.add(ring);
    }

    // Atmosphere glow
    let atmosphere = null;
    if(['venus','jupiter','saturn','uranus','neptune'].includes(planet.id)){
      const atmColors={venus:'#fff4d0',jupiter:'#ffd6b3',saturn:'#f4dfaa',uranus:'#9bf1ef',neptune:'#7fa2ff'};
      const atmPowers={venus:2.0,jupiter:2.6,saturn:2.6,uranus:2.6,neptune:2.6};
      const atmOpac={venus:0.70,jupiter:0.42,saturn:0.42,uranus:0.42,neptune:0.42};
      atmosphere = new THREE.Mesh(geo.clone(), makeAtmosphereMaterial(atmColors[planet.id],atmPowers[planet.id]||2.6,atmOpac[planet.id]||0.42));
      atmosphere.scale.setScalar(planet.id==='venus'?1.12:1.08);
      mesh.add(atmosphere);
    }

    // Glow sprite
    const gc2 = new THREE.Color(planet.color);
    const glowTex = makeDiscGlowTexture(`rgba(${Math.round(gc2.r*255)},${Math.round(gc2.g*255)},${Math.round(gc2.b*255)},0.42)`,'rgba(0,0,0,0)',256);
    const glowMat = new THREE.SpriteMaterial({map:glowTex,blending:THREE.AdditiveBlending,depthWrite:false,transparent:true,opacity:0.72});
    const glowSpr = new THREE.Sprite(glowMat);
    const brightBoost = planet.id==='venus'?0.2:planet.id==='jupiter'?0.12:0.03;
    glowSpr.scale.set(r*(8.6+brightBoost*6),r*(8.6+brightBoost*6),1);
    planetMeshes.push({mesh,glow:glowSpr,ring,atmosphere,planet});
    scene.add(glowSpr);
  });
}

function updatePlanetPositions(date) {
  const T = getJulianCentury((date.getTime()-Date.now())/1000 + (state.timeOffset||0));
  const lst = getLST(date);
  const lstRad = lst*DEG;
  planetMeshes.forEach(({mesh,glow,ring,planet}) => {
    const pos = planetPosition(planet, T);
    const v = raDecToXYZ(pos.ra, pos.dec, SKY_R*0.93);
    const cosL=Math.cos(-lstRad), sinL=Math.sin(-lstRad);
    const rx=v.x*cosL-v.z*sinL, rz=v.x*sinL+v.z*cosL;
    mesh.position.set(rx,v.y,rz);
    glow.position.copy(mesh.position);
    // Axial spin
    mesh.rotation.y += mesh.userData.spinRate||0.0005;
    if(ring) ring.rotation.z += 0.00025;
    // Dynamic glow
    const brightBoost = planet.id==='venus'?0.2:planet.id==='jupiter'?0.12:0.03;
    glow.material.opacity = 0.42+brightBoost;
    glow.scale.setScalar(planet.size*(8.6+brightBoost*6));
    mesh.userData.screenPos = null;
  });
}

/* ── Sky rotation (LST) ── */
const skyGroup = new THREE.Group();
scene.add(skyGroup);
// We'll rotate the whole sky group around Y to simulate Earth's rotation

function getEffectiveDate() {
  const now = Date.now();
  let off = state.timeOffset;
  if (state.playing) {
    off = state._playOff0 + (now - state._playT0) * 0.001 * state.playSpeed;
    state.timeOffset = off;
    updateTimeDisplay(off);
  }
  return new Date(now + off*1000);
}

function getEffectiveLST() {
  return getLST(getEffectiveDate());
}

/* ── Camera control ── */
function updateCamera() {
  // Camera points from origin outward
  const az  = state.azimuth;
  const alt = Math.max(-0.3, Math.min(Math.PI/2*0.98, state.altitude));
  const x = Math.sin(az) * Math.cos(alt);
  const y = Math.sin(alt);
  const z = Math.cos(az) * Math.cos(alt);
  camera.lookAt(new THREE.Vector3(x*100, y*100, z*100));
  // Update compass widget
  drawCompassWidget(az);
  // Update sky overlay if on
  if (_compassOverlayOn) drawCompassOverlay(az);
}


/* ═══════════════════════════════════════════════════════════
   SHOOTING STARS — random meteors
═══════════════════════════════════════════════════════════ */
const _shootingStars = [];
function spawnShootingStar() {
  // Random position on sky sphere
  const ra   = Math.random() * 360;
  const dec  = 20 + Math.random() * 50; // mostly in upper sky
  const v1   = raDecToXYZ(ra, dec, SKY_R * 0.97);
  const v2   = raDecToXYZ(ra + 8 + Math.random()*12, dec - 5 - Math.random()*10, SKY_R * 0.97);

  const geo  = new THREE.BufferGeometry().setFromPoints([v1, v2]);
  const mat  = new THREE.LineBasicMaterial({
    color: 0xffffff, transparent: true, opacity: 0.9,
    blending: THREE.AdditiveBlending, depthWrite: false,
  });
  const line = new THREE.Line(geo, mat);
  scene.add(line);
  _shootingStars.push({ line, mat, t: 0 });
}

function updateShootingStars() {
  for (let i = _shootingStars.length - 1; i >= 0; i--) {
    const ss = _shootingStars[i];
    ss.t += 0.045;
    ss.mat.opacity = Math.max(0, 0.9 - ss.t * 0.9);
    if (ss.t >= 1) {
      scene.remove(ss.line);
      _shootingStars.splice(i, 1);
    }
  }
}

// Spawn a shooting star every 8-22 seconds
function _scheduleShootingStar() {
  const delay = 8000 + Math.random() * 14000;
  setTimeout(() => {
    spawnShootingStar();
    _scheduleShootingStar();
  }, delay);
}


