/* Zenith marker — subtle pulse at zenith */
function buildZenithMarker() {
  const geo = new THREE.RingGeometry(8, 10, 64);
  const mat = new THREE.MeshBasicMaterial({
    color:0x00f7ff, transparent:true, opacity:0.18,
    blending:THREE.AdditiveBlending, depthWrite:false, side:THREE.DoubleSide
  });
  const ring = new THREE.Mesh(geo, mat);
  ring.position.set(0, SKY_R*0.94, 0);
  ring.rotation.x = Math.PI/2;
  ring.userData.isZenith = true;
  scene.add(ring);
  // Animate opacity
  let t = 0;
  setInterval(()=>{
    t += 0.04;
    ring.material.opacity = 0.08 + 0.12*Math.sin(t);
  }, 50);

  // N/E/S/W direction lines on horizon
  const dirs = [{az:0,col:0x00f7ff},{az:90,col:0xffd700},{az:180,col:0xff4757},{az:270,col:0xff9f43}];
  dirs.forEach(({az,col})=>{
    const pts = [];
    for(let r=0;r<=1;r+=0.05){
      const v = new THREE.Vector3(Math.sin(az*DEG)*SKY_R*0.88*(1-r*0.05), -SKY_R*0.015, Math.cos(az*DEG)*SKY_R*0.88*(1-r*0.05));
      pts.push(v);
    }
    const geo2 = new THREE.BufferGeometry().setFromPoints([
      new THREE.Vector3(Math.sin(az*DEG)*SKY_R*0.82, -1, Math.cos(az*DEG)*SKY_R*0.82),
      new THREE.Vector3(Math.sin(az*DEG)*SKY_R*0.88, -1, Math.cos(az*DEG)*SKY_R*0.88),
    ]);
    const mat2 = new THREE.LineBasicMaterial({color:col,transparent:true,opacity:0.35,blending:THREE.AdditiveBlending});
    scene.add(new THREE.Line(geo2,mat2));
  });
}

/* Atmospheric horizon glow */
function buildHorizonGlow() {
  const geo = new THREE.CylinderGeometry(SKY_R*0.90, SKY_R*0.90, SKY_R*0.04, 128, 1, true);
  const mat = new THREE.ShaderMaterial({
    uniforms:{},
    vertexShader:`
      varying float vY;
      void main(){
        vY=position.y;
        gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);
      }`,
    fragmentShader:`
      varying float vY;
      void main(){
        float t=clamp(1.0-abs(vY)*18.0,0.0,1.0);
        gl_FragColor=vec4(0.03,0.15,0.30,t*0.18);
      }`,
    transparent:true, depthWrite:false,
    blending:THREE.AdditiveBlending, side:THREE.BackSide
  });
  scene.add(new THREE.Mesh(geo,mat));
}

/* Star selection highlight ring */
let _selectedStarHighlight = null;
function showStarHighlight(star) {
  if(_selectedStarHighlight) scene.remove(_selectedStarHighlight);
  const v = raDecToXYZ(star.ra, star.dec, SKY_R*0.955);
  const geo = new THREE.RingGeometry(3.2, 5.0, 32);
  const mat = new THREE.MeshBasicMaterial({
    color:0xffd700, transparent:true, opacity:0.7,
    blending:THREE.AdditiveBlending, depthWrite:false, side:THREE.DoubleSide
  });
  _selectedStarHighlight = new THREE.Mesh(geo, mat);
  _selectedStarHighlight.position.copy(v);
  _selectedStarHighlight.lookAt(0,0,0);
  scene.add(_selectedStarHighlight);
  _selectedStarHighlight.rotation.y = starPoints.rotation.y;
  // Pulse it
  let t=0, growing=true;
  const anim = setInterval(()=>{
    if(!_selectedStarHighlight){clearInterval(anim);return;}
    t+=growing?0.08:-0.06;
    if(t>1){growing=false;} if(t<0){growing=true;}
    _selectedStarHighlight.material.opacity = 0.3+t*0.5;
    _selectedStarHighlight.scale.setScalar(0.9+t*0.25);
  },30);
  _selectedStarHighlight.userData.anim = anim;
}
function clearStarHighlight() {
  if(!_selectedStarHighlight) return;
  clearInterval(_selectedStarHighlight.userData.anim);
  scene.remove(_selectedStarHighlight);
  _selectedStarHighlight = null;
}


/* ── Render loop ── */
function animate() {
  requestAnimationFrame(animate);
  const lst = getEffectiveLST();
  const lstRad = lst * DEG;

  // Rotate equatorial positions to local horizontal
  if (starPoints)    starPoints.rotation.y = -lstRad;
  if (milkyWayMesh)  milkyWayMesh.rotation.y = -lstRad;
  if (activeConGroup) activeConGroup.rotation.y = -lstRad;
  if (activeFormationLabelGroup) activeFormationLabelGroup.rotation.y = -lstRad;
  labelGroup.rotation.y = -lstRad;

  _frameCount++;
  if (starPoints?.material?.uniforms?.time) starPoints.material.uniforms.time.value = _frameCount * 0.016;
  const _now = getEffectiveDate();

  // Moon: update every ~1.5s (phase changes imperceptibly faster)
  _moonFrameCount++;
  if (_moonFrameCount >= _moonUpdateEvery || state.playing) {
    _moonFrameCount = 0;
    updateMoonPosition(_now);
  }

  // Planets: update every ~0.5s (orbital motion is very slow)
  _planetFrameCount++;
  if (_planetFrameCount >= _planetUpdateEvery || state.playing) {
    _planetFrameCount = 0;
    updatePlanetPositions(_now);
  }

  updateShootingStars();
  updateImportanceSprites(lstRad);
  updateCamera();
  updateTimeDisplay(state.timeOffset);
  if (_navActive) _updateNavBearing();

  renderer.render(scene, camera);
}

/* ── Raycasting for star clicks ── */
const raycaster = new THREE.Raycaster();
const mouse     = new THREE.Vector2();
raycaster.params.Points.threshold = 8;

function onStarClick(event) {
  const x = event.changedTouches ? event.changedTouches[0].clientX : event.clientX;
  const y = event.changedTouches ? event.changedTouches[0].clientY : event.clientY;
  mouse.set((x/window.innerWidth)*2-1, -(y/window.innerHeight)*2+1);
  raycaster.setFromCamera(mouse, camera);

  // Check moon
  if (moonMesh) {
    const hits = raycaster.intersectObject(moonMesh);
    if (hits.length) { showMoonPanel(moonMesh.userData.moonData); return; }
  }

  // Check planets
  for (const {mesh, planet} of planetMeshes) {
    const ph = raycaster.intersectObject(mesh);
    if (ph.length) { showPlanetPanel(planet); return; }
  }

  // Check stars
  if (!starPoints) return;
  const hits = raycaster.intersectObject(starPoints);
  if (hits.length) {
    const idx = hits[0].index;
    const starId = starPoints.geometry.userData.starIds[idx];
    if (starId) {
      const star = STAR_MAP[starId];
      if (star) {
        showStarHighlight(star);
        if (_experienceMode === 'story' || _experienceMode === 'navigate') {
          openStoryPanel(star);
        } else {
          showStarPanel(star);
        }
      }
    }
  }
}

/* ── Mouse/touch drag ── */
function onPointerDown(e) {
  state.dragging = true;
  state.lastX = e.touches ? e.touches[0].clientX : e.clientX;
  state.lastY = e.touches ? e.touches[0].clientY : e.clientY;
  state._pointerDownX = state.lastX; state._pointerDownY = state.lastY;
  document.getElementById('cursor')?.classList.add('drag');
}
function onPointerMove(e) {
  const cx = e.touches ? e.touches[0].clientX : e.clientX;
  const cy = e.touches ? e.touches[0].clientY : e.clientY;
  // Update custom cursor
  const cur = document.getElementById('cursor');
  if (cur) { cur.style.left = cx+'px'; cur.style.top = cy+'px'; }
  // Hover tooltip
  updateHoverTooltip(cx, cy);

  if (!state.dragging) return;
  const dx = cx - state.lastX;
  const dy = cy - state.lastY;
  const sens = 0.003 / (state.fov/70);
  state.azimuth  -= dx * sens;
  state.altitude  = Math.max(-0.25, Math.min(Math.PI/2, state.altitude + dy * sens));
  state.lastX = cx; state.lastY = cy;
  /* Rotate bird cursor to face drag direction */
  if (Math.hypot(dx,dy) > 2) {
    const birdAngle = Math.atan2(dx, -dy) * 180/Math.PI - 38;
    const img = document.querySelector('#cursor img');
    if (img) img.style.transform = `rotate(${birdAngle}deg)`;
  }
}
function onPointerUp(e) {
  state.dragging = false;
  document.getElementById('cursor')?.classList.remove('drag');
  // Short tap = click
  const cx = e.changedTouches ? e.changedTouches[0].clientX : e.clientX;
  const cy = e.changedTouches ? e.changedTouches[0].clientY : e.clientY;
  const dist = Math.hypot(cx-(state._pointerDownX||cx), cy-(state._pointerDownY||cy));
  if (dist < 12) onStarClick(e);
}

function onWheel(e) {
  state.fov = Math.max(20, Math.min(110, state.fov + e.deltaY * 0.05));
  camera.fov = state.fov; camera.updateProjectionMatrix();
}

let _pinchDist = 0;
function onTouchStart(e) {
  if (e.touches.length === 2) {
    _pinchDist = Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);
    state.dragging = false;
  } else { onPointerDown(e); }
}
function onTouchMove(e) {
  if (e.touches.length === 2) {
    const d = Math.hypot(e.touches[0].clientX-e.touches[1].clientX,e.touches[0].clientY-e.touches[1].clientY);
    state.fov = Math.max(20, Math.min(110, state.fov * (_pinchDist/d)));
    camera.fov = state.fov; camera.updateProjectionMatrix();
    _pinchDist = d;
  } else { onPointerMove(e); }
}

renderer.domElement.addEventListener('mousedown',  onPointerDown);
window.addEventListener('mousemove',    onPointerMove);
window.addEventListener('mouseup',      onPointerUp);
renderer.domElement.addEventListener('wheel',      e=>{e.preventDefault();onWheel(e);},{passive:false});
renderer.domElement.addEventListener('touchstart', e=>{e.preventDefault();onTouchStart(e);},{passive:false});
renderer.domElement.addEventListener('touchmove',  e=>{e.preventDefault();onTouchMove(e);},{passive:false});
renderer.domElement.addEventListener('touchend',   onPointerUp,{passive:true});
window.addEventListener('resize', () => {
  renderer.setSize(window.innerWidth, window.innerHeight);
  camera.aspect = window.innerWidth/window.innerHeight;
  camera.updateProjectionMatrix();
});

/* ── Hover tooltip ── */
function updateHoverTooltip(cx, cy) {
  mouse.set((cx/window.innerWidth)*2-1, -(cy/window.innerHeight)*2+1);
  raycaster.setFromCamera(mouse, camera);
  const tooltip = document.getElementById('tooltip');
  if (!tooltip) return;

  // Moon check
  if (moonMesh) {
    const mh = raycaster.intersectObject(moonMesh);
    if (mh.length) {
      const md = moonMesh.userData.moonData;
      if (md) tooltip.textContent = `☽ ${md.hawaiiNight} · ${Math.round(md.illum*100)}% · ${md.phaseName}`;
      tooltip.classList.add('show');
      tooltip.style.left = cx+'px'; tooltip.style.top = cy+'px';
      document.getElementById('cursor')?.classList.add('hover');
      return;
    }
  }

  // Planet check
  for (const {mesh,planet} of planetMeshes) {
    const ph=raycaster.intersectObject(mesh);
    if(ph.length){tooltip.textContent=planet.h?`${planet.h} (${planet.name})`:`${planet.name} — mag ~${planet.id==='uranus'?5.7:planet.id==='neptune'?8:2}`;tooltip.classList.add('show');tooltip.style.left=cx+'px';tooltip.style.top=cy+'px';document.getElementById('cursor')?.classList.add('hover');return;}
  }
  // Star check
  if (starPoints) {
    const hits = raycaster.intersectObject(starPoints);
    if (hits.length) {
      const idx = hits[0].index;
      const sid = starPoints.geometry.userData.starIds[idx];
      const star = sid ? STAR_MAP[sid] : null;
      if (star) {
        tooltip.textContent = star.h ? `${star.h} · ${star.id}` : star.id;
        tooltip.classList.add('show');
        tooltip.style.left = cx+'px'; tooltip.style.top = cy+'px';
        document.getElementById('cursor')?.classList.add('hover');
        return;
      }
    }
  }

  tooltip.classList.remove('show');
  document.getElementById('cursor')?.classList.remove('hover');
}


