/* ── Culture switching with fade transition ── */
let _conFadeOutTimer = null;
function switchCulture(cultureId) {
  if (!CULTURES[cultureId]) return;
  state.culture = cultureId;

  cosmicWeaveTransition(() => {
    // Fade out active group
    if (activeConGroup) {
      const mats = [];
      activeConGroup.children.forEach(c => { if(c.material) mats.push(c.material); });
      mats.forEach(m => m.opacity = 0);
    }
    buildConstellationLines(cultureId);
    buildStarLabels(cultureId);
    // Fade in
    if (activeConGroup) {
      const newMats = [];
      activeConGroup.children.forEach(c => { if(c.material) newMats.push(c.material); });
      newMats.forEach(m => { m._baseOp = m.opacity; m.opacity = 0; });
      let s = 0;
      const fi = setInterval(() => {
        s++;
        newMats.forEach(m => { const t=m._baseOp||0.75; m.opacity=Math.min(t,(s/12)*t); });
        if (s >= 12) clearInterval(fi);
      }, 20);
    }
  });

  // Update UI
  document.querySelectorAll('.cult-btn').forEach(b => {
    b.classList.toggle('active', b.dataset.culture === cultureId);
  });
  if (document.getElementById('formation-panel')?.classList.contains('show')) {
    _focusCulture = cultureId;
    renderFormationFocus();
  }
}

