function updateTimeDisplay(off) {
  // Only update DOM at reduced cadence (not every frame)
  if (_frameCount % 6 !== 0 && !state.playing) return;
  const sliderEl = _dom['tp-slider'] || document.getElementById('tp-slider');
  const labelEl  = _dom['tp-label']  || document.getElementById('tp-label');
  if (sliderEl && !state.playing) sliderEl.value = String(Math.round(off));
  const h = Math.round(off/3600);
  if (labelEl) labelEl.textContent = Math.abs(off)<30 ? 'NOW' : (h>=0?'+':'')+h+'h';
  if (_frameCount % 30 !== 0) return;  // clock at ~2fps is fine
  const d = getEffectiveDate();
  const td = _dom['time-display'], dd = _dom['date-display'];
  if (td) td.textContent = d.toLocaleTimeString('en-US',{hour:'2-digit',minute:'2-digit'});
  if (dd) dd.textContent = d.toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
}

/* ── Compass widget ── */
/* Cached processed compass image */
let _compassImg = null, _compassProcessed = false, _iwaForCompass = null;

function processCompassImage(src, callback) {
  if (_compassImg !== null) { callback(_compassImg); return; }
  /* Load real Nainoa Thompson star compass, white→transparent, darks→cyan-tinted */
  const img = new Image();
  img.onload = () => {
    try {
      const cv = document.createElement('canvas');
      cv.width = img.naturalWidth; cv.height = img.naturalHeight;
      const ctx = cv.getContext('2d');
      ctx.drawImage(img, 0, 0);
      const id = ctx.getImageData(0, 0, cv.width, cv.height), d = id.data;
      for (let i = 0; i < d.length; i += 4) {
        const lum = (d[i]*.299 + d[i+1]*.587 + d[i+2]*.114) / 255;
        if (lum > 0.82) {
          d[i+3] = 0;  // white background → transparent
        } else if (lum > 0.5) {
          d[i+3] = Math.round((1 - lum) * 255 * 1.8);  // mid tones → semi-transparent
        } else {
          // dark pixels: keep opacity, tint slightly cyan
          const str = Math.min(1, (1 - lum) * 1.2);
          d[i]   = Math.round(d[i]   * (1 - str*.3));
          d[i+1] = Math.round(d[i+1] * (1 - str*.3) + 247 * str*.3);
          d[i+2] = Math.round(d[i+2] * (1 - str*.3) + 255 * str*.3);
        }
      }
      ctx.putImageData(id, 0, 0);
      _compassProcessed = true;
      const dataUrl = cv.toDataURL();
      const loaded = new Image();
      loaded.onload = () => { _compassImg = loaded; callback(_compassImg); };
      loaded.src = dataUrl;
    } catch(e) { console.warn('Compass processing failed:', e); _compassImg = false; callback(null); }
  };
  img.onerror = () => { _compassImg = false; callback(null); };
  img.src = _COMPASS_DATA_URL;  // embedded — no network request
}
function processIwaForCursor(src, callback) {
  /* Load real ʻiwa tribal silhouette, convert dark pixels → cyan */
  const tmp = new Image();
  tmp.onload = () => {
    try {
      const cv = document.createElement('canvas');
      cv.width = tmp.naturalWidth; cv.height = tmp.naturalHeight;
      const ctx = cv.getContext('2d');
      ctx.drawImage(tmp, 0, 0);
      const id = ctx.getImageData(0, 0, cv.width, cv.height), d = id.data;
      for (let i = 0; i < d.length; i += 4) {
        const lum = (d[i]*.299 + d[i+1]*.587 + d[i+2]*.114) / 255;
        if (lum > 0.55) {
          d[i+3] = 0;  // white background → transparent
        } else {
          const str = 1 - lum / 0.55;
          d[i]   = 0;
          d[i+1] = Math.round(247 * str);  // cyan: rgb(0, 247, 255)
          d[i+2] = Math.round(255 * str);
          d[i+3] = Math.round(245 * str);
        }
      }
      ctx.putImageData(id, 0, 0);
      callback(cv.toDataURL());
    } catch(e) { console.warn('ʻIwa processing failed:', e); callback(null); }
  };
  tmp.onerror = () => { console.warn('ʻIwa load failed'); callback(null); };
  tmp.src = _IWA_DATA_URL;  // embedded — no network request
}
function drawCompassWidget(azRad) {
  const c = document.getElementById('compass-canvas');
  if (!c) return;
  const ctx = c.getContext('2d');
  const W = 316, H = 316, cx = 158, cy = 158;
  ctx.clearRect(0, 0, W, H);

  if (_compassImg) {
    // Rotate the compass image based on camera look direction
    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate(-azRad);
    ctx.globalAlpha = 0.78;
    ctx.drawImage(_compassImg, -cx, -cy, W, H);
    ctx.globalAlpha = 1;
    ctx.restore();
  } else {
    // Fallback: draw basic compass ring
    ctx.beginPath(); ctx.arc(cx,cy,140,0,Math.PI*2);
    ctx.strokeStyle='rgba(0,247,255,0.3)'; ctx.lineWidth=2; ctx.stroke();
    ['N','E','S','W'].forEach((l,i)=>{
      const a=i*Math.PI/2-azRad;
      const colors=['#00f7ff','#ffd700','#ff4757','#ff9f43'];
      ctx.save(); ctx.translate(cx+Math.sin(a)*115,cy-Math.cos(a)*115);
      ctx.fillStyle=colors[i]; ctx.font='bold 13px Orbitron,monospace';
      ctx.textAlign='center'; ctx.textBaseline='middle'; ctx.fillText(l,0,0); ctx.restore();
    });
  }

  // ʻIwa bird at the center — cyan silhouette with canvas fallback
  {
    const birdW = W * 0.28;
    if (_iwaForCompass && _iwaForCompass.complete && _iwaForCompass.naturalWidth > 0) {
      const bh2 = birdW * (_iwaForCompass.naturalHeight / Math.max(1, _iwaForCompass.naturalWidth));
      ctx.save();
      ctx.shadowColor = 'rgba(0,247,255,0.75)'; ctx.shadowBlur = 16;
      ctx.globalAlpha = 0.93;
      ctx.drawImage(_iwaForCompass, cx - birdW/2, cy - bh2/2, birdW, bh2);
      ctx.shadowBlur = 0; ctx.restore();
    } else {
      // Inline canvas bird silhouette (shows when image unavailable)
      const s = birdW / 76;
      ctx.save(); ctx.translate(cx, cy); ctx.scale(s, s);
      ctx.fillStyle = 'rgba(0,247,255,0.85)';
      ctx.shadowColor = 'rgba(0,247,255,0.65)'; ctx.shadowBlur = 12;
      // body
      ctx.beginPath(); ctx.ellipse(0, 8, 22, 10, 0, 0, Math.PI*2); ctx.fill();
      // head
      ctx.beginPath(); ctx.ellipse(22, 0, 10, 8, 0, 0, Math.PI*2); ctx.fill();
      // beak
      ctx.beginPath(); ctx.moveTo(30,-2); ctx.lineTo(46,-5); ctx.lineTo(46,0); ctx.lineTo(34,2); ctx.closePath(); ctx.fill();
      // left wing
      ctx.beginPath(); ctx.moveTo(-2,-4); ctx.quadraticCurveTo(-30,-26, 4,-22); ctx.quadraticCurveTo(-20,-10,-2,-4); ctx.fill();
      // right wing
      ctx.beginPath(); ctx.moveTo(2,-4); ctx.quadraticCurveTo(30,-26,-4,-22); ctx.quadraticCurveTo(20,-10,2,-4); ctx.fill();
      ctx.shadowBlur = 0; ctx.restore();
    }
    // Update look-direction house label
    const ldEl = document.getElementById('compass-look-dir');
    if (ldEl) {
      const deg = ((state.azimuth * 180/Math.PI) % 360 + 360) % 360;
      const hns = ['ʻAKAU','HAKA','NĀ LEO','NALANI','MANU','NOIO','ʻAINA','LĀ',
                   'HIKINA','LĀ','ʻAINA','NOIO','MANU','NALANI','NĀ LEO','HAKA',
                   'HEMA','HAKA','NĀ LEO','NALANI','MANU','NOIO','ʻAINA','LĀ',
                   'KOMOHANA','LĀ','ʻAINA','NOIO','MANU','NALANI','NĀ LEO','HAKA'];
      ldEl.textContent = hns[Math.round(deg/11.25) % 32];
    }
  }

  // Look direction indicator (small arc)
  ctx.save(); ctx.translate(cx,cy);
  ctx.strokeStyle='rgba(0,247,255,0.6)'; ctx.lineWidth=2.5;
  ctx.beginPath(); ctx.arc(0,0,128,-azRad-0.08,-azRad+0.08);
  ctx.stroke();
  // Dot on direction
  const dx=Math.sin(azRad)*134, dy=-Math.cos(azRad)*134;
  ctx.beginPath(); ctx.arc(dx,dy,4,0,Math.PI*2);
  ctx.fillStyle='rgba(0,247,255,0.8)'; ctx.fill();
  ctx.restore();
}

/* ── Loading sequence ── */
/* ═══════════════════════════════════════════════════════════
   EXPERIENCE MODE SYSTEM
═══════════════════════════════════════════════════════════ */
let _experienceMode = 'explore';

function setExperienceMode(mode) {
  const prev = _experienceMode;
  _experienceMode = mode;

  // Update pills
  document.querySelectorAll('.mode-pill').forEach(p => {
    p.classList.toggle('active', p.dataset.mode === mode);
  });

  // Culture switcher visibility
  const cs = document.getElementById('culture-switcher');
  if (cs) { cs.style.transition='top .32s cubic-bezier(.4,0,.2,1)'; cs.style.top = mode === 'navigate' ? '-110px' : ''; }

  // Show/hide mode-specific UI
  document.getElementById('nav-hud').classList.toggle('active', mode === 'navigate');
  document.getElementById('seasonal-badge').classList.toggle('show', mode === 'seasonal');

  if (mode === 'navigate') {
    _enterNavMode();
  } else if (prev === 'navigate') {
    _exitNavMode();
  }

  if (mode === 'seasonal') {
    _enterSeasonalMode();
  }

  if (mode === 'tour') {
    startTour();
  } else {
    endTour();
  }

  if (mode === 'story') {
    // Show story for the most prominent star in view
    _openStoryForBestStar();
  }

  navigator.vibrate?.(6);
}

document.querySelectorAll('.mode-pill').forEach(btn => {
  btn.addEventListener('click', () => setExperienceMode(btn.dataset.mode));
});

/* ═══════════════════════════════════════════════════════════
   STORY PANEL — Moʻolelo-first presentation
═══════════════════════════════════════════════════════════ */
function openStoryPanel(star) {
  const culture = CULTURES[state.culture] || CULTURES.hawaiian;
  const formation = getBestFormationForCulture(state.culture, star.id);
  const tier = STAR_TIERS[star.id];
  const cults = star.cults || {};

  // Star color
  const isRed = star.id==='Betelgeuse'||star.id==='Antares'||star.id==='Aldebaran'||star.id==='Gacrux';
  const isBlue = star.id==='Rigel'||star.id==='Spica'||star.id==='Sirius';
  const starCol = star.id==='Arcturus'?'#ffd700':isRed?'#ff9966':isBlue?'#aaccff':
    (tier?.glowColor||'#a0c8f0');
  const glowCSS = `--sg:${starCol}44`;

  // Culture badge
  document.getElementById('story-culture-badge').textContent =
    `${culture.name} · ${['hawaiian','polynesian'].includes(state.culture)?'Pacific Navigation':'Cultural Sky'}`;

  // Build moʻolelo-first content
  const hasHawName = !!star.h;
  const displayName = (state.culture !== 'western' && hasHawName) ? star.h : star.id;
  const tradKeys = Object.keys(cults).filter(k=>k!=='note'&&cults[k]);

  let content = '';

  // Visual hero
  content += `<div id="story-star-visual">
    <div class="story-star-glow-ring" style="${glowCSS}">
      <div class="story-star-core" style="background:${starCol};color:${starCol};width:${tier?22+tier.tier*2:22}px;height:${tier?22+tier.tier*2:22}px;"></div>
    </div>
  </div>`;

  // Primary name (Hawaiian first)
  content += `<div id="story-haw-name">${esc(displayName)}</div>`;
  if (star.meaning) content += `<div id="story-meaning">"${esc(star.meaning)}"</div>`;
  if (displayName !== star.id) content += `<div style="text-align:center;font-size:.75rem;color:rgba(255,255,255,.35);font-family:var(--orb);letter-spacing:.08em;margin-top:-6px;">${esc(star.id)} · ${esc(star.con)}</div>`;

  // Confidence
  const conf = 'verified'; // stars with Hawaiian names are documented
  content += `<div style="display:flex;justify-content:center;gap:8px;flex-wrap:wrap;">
    <span class="story-conf-badge conf-${hasHawName?'verified':'probable'}">${hasHawName?'✓ Verified Hawaiian Name':'Astronomical Record'}</span>
    ${tier?`<span class="story-conf-badge conf-verified">Tier ${tier.tier} Navigation Star</span>`:''}
  </div>`;

  // MOOLELO FIRST — the story before the science
  if (star.moolelo) {
    content += `<div style="display:flex;flex-direction:column;gap:6px;">
      <div class="story-trad-title"><i class="fas fa-scroll" style="color:rgba(232,201,106,.5)"></i> Moʻolelo — The Story</div>
      <div id="story-moolelo-text">${esc(star.moolelo)}</div>
    </div>`;
  }

  // Navigation use
  if (star.nav) {
    content += `<div class="story-nav-box">
      <div class="story-nav-icon"><i class="fas fa-compass" style="color:rgba(232,201,106,.6)"></i></div>
      <div class="story-nav-text">${esc(star.nav)}</div>
    </div>`;
  }

  // Formation context
  if (formation) {
    const exact = formation.stars?.includes(star.id);
    content += `<div class="story-trad-block">
      <div class="story-trad-title"><i class="fas fa-star" style="color:${culture.textColor||'#00f7ff'}"></i> ${esc(culture.name)} — ${esc(formation.name)}</div>
      <div style="font-size:.8rem;line-height:1.68;color:rgba(200,225,245,.82);">${esc(formation.moolelo||'')}</div>
      ${formation.navUse?`<div class="story-nav-box" style="margin-top:10px;"><div class="story-nav-icon"><i class="fas fa-ship" style="color:rgba(232,201,106,.5)"></i></div><div class="story-nav-text">${esc(formation.navUse)}</div></div>`:''}
      ${!exact?`<div style="font-size:.68rem;color:rgba(255,215,0,.45);font-style:italic;margin-top:6px;">Nearest ${esc(culture.name)} formation to this star.</div>`:''}
    </div>`;
  }

  // Astronomical facts — AFTER the cultural content
  const facts = [
    ['Star Type', star.type],
    ['Distance', star.distance_ly?`${Number(star.distance_ly).toLocaleString()} light years`:null],
    ['Spectral', star.spectral],
    ['Magnitude', star.mag?.toFixed?`${star.mag.toFixed(2)} (brightness)`:null],
  ].filter(([,v])=>v);
  if (facts.length) {
    content += `<div style="display:flex;flex-direction:column;gap:6px;">
      <div class="story-trad-title"><i class="fas fa-telescope" style="color:rgba(0,247,255,.45)"></i> Scientific Record</div>
      <div class="story-fact-row">${facts.map(([l,v])=>`<div class="story-fact"><div class="story-fact-lbl">${esc(l)}</div><div class="story-fact-val">${esc(v)}</div></div>`).join('')}</div>
    </div>`;
  }

  // Cross-tradition knowledge
  if (tradKeys.length) {
    content += `<div class="story-trad-block">
      <div class="story-trad-title"><i class="fas fa-globe" style="color:rgba(0,247,255,.45)"></i> Across Traditions</div>
      ${tradKeys.map(k=>`<div class="story-trad-item">
        <span class="story-trad-name">${esc(k.charAt(0).toUpperCase()+k.slice(1))}</span>
        <span>${esc(cults[k])}</span>
      </div>`).join('')}
    </div>`;
  }

  if (cults.note) {
    content += `<div style="font-size:.72rem;color:rgba(255,255,255,.38);font-style:italic;padding:8px 12px;border-radius:8px;background:rgba(255,255,255,.025);border:1px solid rgba(255,255,255,.05);line-height:1.6;"><i class="fas fa-circle-info" style="margin-right:5px;opacity:.5;"></i>${esc(cults.note)}</div>`;
  }

  // Formation focus action button
  content += `<div style="padding:4px 0 16px;">
    <button onclick="openFormationFocus(STAR_MAP['${star.id}'])" style="width:100%;padding:13px;border-radius:14px;border:1px solid rgba(0,247,255,.3);background:rgba(0,247,255,.06);color:rgba(0,247,255,.88);font-family:var(--orb);font-size:.68rem;letter-spacing:.07em;cursor:pointer;touch-action:manipulation;transition:background .15s;">
      <i class="fas fa-diagram-project"></i> Formation Focus — ${esc(state.culture==='western'?star.id:(star.h||star.id))}
    </button>
  </div>`;

  document.getElementById('story-content').innerHTML = content;
  document.getElementById('story-panel').classList.add('show');
  document.getElementById('story-content').scrollTop = 0;
  showStarHighlight(star);
}

function closeStoryPanel() {
  document.getElementById('story-panel').classList.remove('show');
  clearStarHighlight();
  if (_experienceMode === 'story') {
    document.querySelectorAll('.mode-pill').forEach(p => p.classList.toggle('active', p.dataset.mode === 'explore'));
    _experienceMode = 'explore';
  }
}

function _openStoryForBestStar() {
  // Find most important star in current view
  const az = state.azimuth, alt = state.altitude;
  let best = null, bestScore = Infinity;
  STARS.forEach(s => {
    const tier = STAR_TIERS[s.id];
    if (!tier || tier.tier > 2) return;
    const starAz = risingAzimuth(s.dec);
    if (starAz === null) return;
    const score = tier.tier * 10;
    if (score < bestScore) { bestScore = score; best = s; }
  });
  if (best) {
    openStoryPanel(best);
  } else {
    // Default to Arcturus
    openStoryPanel(STAR_MAP['Arcturus']);
  }
}

/* ═══════════════════════════════════════════════════════════
   COSMIC WEAVE TRANSITION — animated culture switch
═══════════════════════════════════════════════════════════ */
function cosmicWeaveTransition(callback) {
  const ovl = document.getElementById('weave-overlay');
  ovl.classList.add('pulse');
  // Particle burst effect via quick opacity flicker on star field
  if (starPoints) {
    const mat = starPoints.material;
    let t = 0;
    const flash = setInterval(() => {
      t++;
      mat.uniforms.opacity.value = 0.5 + 0.5 * Math.sin(t * 0.8);
      if (t > 18) { clearInterval(flash); mat.uniforms.opacity.value = 1; }
    }, 30);
  }
  setTimeout(() => {
    callback();
    setTimeout(() => { ovl.classList.remove('pulse'); }, 500);
  }, 280);
}

/* ═══════════════════════════════════════════════════════════
   NAVIGATION MODE
═══════════════════════════════════════════════════════════ */
const NAV_STARS = [
  { id:'Polaris',    use:'TRUE NORTH — altitude = latitude', bearing:'ʻAKAU (N)', tier:1 },
  { id:'Arcturus',   use:'ZENITH star of Hawaiʻi — home latitude', bearing:'Overhead 21°N', tier:1 },
  { id:'Sirius',     use:'South bearing star — HEMA direction', bearing:'HEMA (S)', tier:1 },
  { id:'Alnilam',    use:'East bearing — rises due east', bearing:'HIKINA (E)', tier:1 },
  { id:'Vega',       use:'Summer overhead reference', bearing:'High NE', tier:2 },
  { id:'Antares',    use:'Summer south bearing', bearing:'HEMA (S)', tier:2 },
  { id:'Canopus',    use:'Deep south latitude star', bearing:'HEMA (S)', tier:2 },
];

let _navActive = false;
let _navTargetStar = null;

function _enterNavMode() {
  _navActive = true;
  const list = document.getElementById('nav-stars-list');
  list.innerHTML = NAV_STARS.map(ns => {
    const star = STAR_MAP[ns.id];
    if (!star) return '';
    return `<div class="nav-star-card${ns.tier===1?' border-gold':''}" data-star="${ns.id}" onclick="navFocusStar('${ns.id}')">
      <div class="nsc-name">${star.h||star.id}</div>
      <div class="nsc-bearing">${ns.bearing}</div>
      <div class="nsc-use">${ns.use}</div>
    </div>`;
  }).join('');
  _updateNavBearing();
}

function _exitNavMode() {
  _navActive = false;
  _navTargetStar = null;
  document.querySelectorAll('.nav-star-card').forEach(c => c.classList.remove('active'));
}

function navFocusStar(starId) {
  _navTargetStar = STAR_MAP[starId];
  document.querySelectorAll('.nav-star-card').forEach(c =>
    c.classList.toggle('active', c.dataset.star === starId)
  );
  showStarHighlight(STAR_MAP[starId]);
  navigator.vibrate?.([6, 20, 8]);
}

const _NAV_HOUSES = ['ʻAKAU','HAKA','NĀ LEO','NALANI','MANU','NOIO','ʻAINA','LĀ','HIKINA','LĀ','ʻAINA','NOIO','MANU','NALANI','NĀ LEO','HAKA','HEMA','HAKA','NĀ LEO','NALANI','MANU','NOIO','ʻAINA','LĀ','KOMOHANA','LĀ','ʻAINA','NOIO','MANU','NALANI','NĀ LEO','HAKA'];
function _updateNavBearing() {
  if (!_navActive) return;
  const deg = (((state.azimuth * 180/Math.PI) % 360) + 360) % 360;
  const houseIdx = Math.round(deg/11.25) % 32;
  const houseEl = _dom['nav-house']  || document.getElementById('nav-house');
  const degEl   = _dom['nav-deg']    || document.getElementById('nav-deg');
  const ldEl    = _dom['compass-look-dir'] || document.getElementById('compass-look-dir');
  if (houseEl) houseEl.textContent = _NAV_HOUSES[houseIdx] || '';
  if (degEl)   degEl.textContent   = deg.toFixed(0) + '°';
  if (ldEl)    ldEl.textContent    = _NAV_HOUSES[houseIdx] || '';
}

/* ═══════════════════════════════════════════════════════════
   SEASONAL MODE
═══════════════════════════════════════════════════════════ */
function _enterSeasonalMode() {
  const now = new Date();
  const month = now.getMonth() + 1;
  // Find best matching event
  let best = SEASONAL_EVENTS.reduce((b, e) => {
    const dist = Math.min(Math.abs(e.month - month), 12 - Math.abs(e.month - month));
    const bdist = Math.min(Math.abs(b.month - month), 12 - Math.abs(b.month - month));
    return dist < bdist ? e : b;
  });

  // Switch to Hawaiian layer
  if (state.culture !== 'hawaiian') switchCulture('hawaiian');

  // Update badge
  document.getElementById('seasonal-badge-text').textContent = best.name;

  // Show banner
  const banner = document.getElementById('seasonal-banner');
  document.getElementById('seasonal-banner-title').textContent = best.name;
  document.getElementById('seasonal-banner-text').textContent = best.desc;
  banner.classList.add('show');

  // Highlight the star
  if (best.starId && STAR_MAP[best.starId]) {
    showStarHighlight(STAR_MAP[best.starId]);
    setTimeout(() => {
      // Point camera toward the event
      if (best.action === 'look_east') { state.azimuth = Math.PI*0.5; state.altitude = 0.2; }
      if (best.action === 'look_south') { state.azimuth = Math.PI; state.altitude = 0.25; }
      if (best.action === 'look_zenith') { state.altitude = Math.PI/2*0.9; }
    }, 600);
  }

  setTimeout(() => { banner.classList.remove('show'); }, 8000);
}

/* ═══════════════════════════════════════════════════════════
   GUIDED TOUR SYSTEM
═══════════════════════════════════════════════════════════ */
let _tourStep = 0, _tourActive = false;
let _tourCameraAnim = null;

function startTour() {
  _tourActive = true;
  _tourStep = 0;
  _renderTourStep();
  // Switch to Hawaiian culture
  if (state.culture !== 'hawaiian') switchCulture('hawaiian');
}

function endTour() {
  _tourActive = false;
  const card = document.getElementById('tour-card');
  card.classList.remove('show');
  clearStarHighlight();
  if (_tourCameraAnim) { clearTimeout(_tourCameraAnim); _tourCameraAnim = null; }
  if (_experienceMode === 'tour') {
    _experienceMode = 'explore';
    document.querySelectorAll('.mode-pill').forEach(p => p.classList.toggle('active', p.dataset.mode === 'explore'));
  }
}

function tourNext() {
  _tourStep++;
  if (_tourStep >= TOUR_STEPS.length) { endTour(); return; }
  _renderTourStep();
}

function _renderTourStep() {
  const step = TOUR_STEPS[_tourStep];
  if (!step) return;
  const card = document.getElementById('tour-card');
  card.classList.add('show');

  document.getElementById('tour-step-num').textContent = `STEP ${_tourStep+1} OF ${TOUR_STEPS.length}`;
  document.getElementById('tour-step-title').textContent = step.title;
  document.getElementById('tour-step-text').textContent = step.text;

  // Progress dots
  document.getElementById('tour-progress-dots').innerHTML =
    TOUR_STEPS.map((_,i)=>`<div class="tour-dot${i===_tourStep?' active':''}"></div>`).join('');

  // Animate camera to step position
  if (step.az !== undefined) {
    const targetAz = step.az, targetAlt = step.alt !== undefined ? step.alt : state.altitude;
    const startAz = state.azimuth, startAlt = state.altitude;
    let t = 0;
    const anim = setInterval(() => {
      t += 0.04;
      if (t >= 1) { t = 1; clearInterval(anim); }
      const ease = t < 0.5 ? 2*t*t : -1+(4-2*t)*t; // ease-in-out
      state.azimuth  = startAz  + (targetAz  - startAz)  * ease;
      state.altitude = startAlt + (targetAlt - startAlt) * ease;
    }, 16);
  }

  // Highlight star
  if (step.highlight && STAR_MAP[step.highlight]) {
    setTimeout(() => showStarHighlight(STAR_MAP[step.highlight]), 400);
  } else {
    clearStarHighlight();
  }

  // Zoom
  if (step.zoom) {
    state.fov = 70 / step.zoom;
    camera.fov = state.fov;
    camera.updateProjectionMatrix();
  } else {
    state.fov = 70;
    camera.fov = 70;
    camera.updateProjectionMatrix();
  }
  navigator.vibrate?.(8);
}

/* ═══════════════════════════════════════════════════════════
   STAR IMPORTANCE RENDERING — glow sprites by tier
═══════════════════════════════════════════════════════════ */
const _tierSprites = new Map();

function buildImportanceSprites() {
  Object.entries(STAR_TIERS).forEach(([starId, info]) => {
    const star = STAR_MAP[starId];
    if (!star) return;
    const r = 8 + (3 - info.tier) * 6; // tier 1 = 14, tier 2 = 8
    const col = new THREE.Color(info.glowColor || '#00f7ff');
    const canvas = document.createElement('canvas');
    canvas.width = canvas.height = 128;
    const ctx = canvas.getContext('2d');
    const g = ctx.createRadialGradient(64,64,0,64,64,64);
    g.addColorStop(0, `rgba(${Math.round(col.r*255)},${Math.round(col.g*255)},${Math.round(col.b*255)},0.7)`);
    g.addColorStop(0.35, `rgba(${Math.round(col.r*255)},${Math.round(col.g*255)},${Math.round(col.b*255)},0.2)`);
    g.addColorStop(1, 'rgba(0,0,0,0)');
    ctx.fillStyle = g; ctx.fillRect(0,0,128,128);
    const tex = new THREE.CanvasTexture(canvas);
    const mat = new THREE.SpriteMaterial({
      map:tex, blending:THREE.AdditiveBlending,
      depthWrite:false, transparent:true, opacity:0.65, depthTest:false
    });
    const sprite = new THREE.Sprite(mat);
    const sz = r * info.glowSize;
    sprite.scale.set(sz, sz, 1);
    const v = raDecToXYZ(star.ra, star.dec, SKY_R*0.961);
    sprite.position.copy(v);
    sprite.renderOrder = 1;
    scene.add(sprite);
    _tierSprites.set(starId, sprite);
  });
}

/* Rotate importance sprites with the star field */
function updateImportanceSprites(lstRad) {
  _tierSprites.forEach((sprite, starId) => {
    const star = STAR_MAP[starId];
    if (!star) return;
    const v = raDecToXYZ(star.ra, star.dec, SKY_R * 0.961);
    const cosL = Math.cos(-lstRad), sinL = Math.sin(-lstRad);
    sprite.position.set(v.x*cosL - v.z*sinL, v.y, v.x*sinL + v.z*cosL);
  });
}



/* ══════════════════════════════════════════════════════════
   GYROSCOPE — DeviceOrientation for mobile AR sky view
   When active: phone acts as a window into the real sky
══════════════════════════════════════════════════════════ */
let _gyroActive     = false;
let _gyroAlpha0     = null;   // calibration offset
let _gyroGranted    = false;
let _lastGyroAlpha  = 0;
let _lastGyroBeta   = 0;
let _lastGyroGamma  = 0;
const _GYRO_SMOOTH  = 0.12;  // lerp factor — lower = smoother, higher = more responsive

function initGyroscope() {
  // iOS 13+ requires explicit permission
  if (typeof DeviceOrientationEvent !== 'undefined' &&
      typeof DeviceOrientationEvent.requestPermission === 'function') {
    DeviceOrientationEvent.requestPermission()
      .then(state => {
        if (state === 'granted') _attachGyro();
        else _showGyroPrompt('Permission denied. Enable in Settings → Privacy → Motion & Orientation.');
      })
      .catch(() => _showGyroPrompt('Could not request motion permission.'));
  } else if (typeof DeviceOrientationEvent !== 'undefined') {
    _attachGyro();  // Android — no permission needed
  } else {
    _showGyroPrompt('No gyroscope detected on this device.');
  }
}

function _attachGyro() {
  window.addEventListener('deviceorientation', _onGyro, true);
  _gyroGranted = true;
  _gyroActive  = true;
  _gyroAlpha0  = null;  // reset calibration
  document.getElementById('btn-gyro')?.classList.add('active');
  // Disable touch drag while gyro is active
  _showGyroHint();
  console.log('[IKE] Gyroscope active');
}

function _detachGyro() {
  window.removeEventListener('deviceorientation', _onGyro, true);
  _gyroActive = false;
  document.getElementById('btn-gyro')?.classList.remove('active');
  document.getElementById('gyro-hint')?.remove();
}

function toggleGyro() {
  if (_gyroActive) { _detachGyro(); return; }
  initGyroscope();
}

function _onGyro(e) {
  if (!_gyroActive) return;
  const alpha = e.alpha || 0;   // compass bearing 0–360 (Z axis)
  const beta  = e.beta  || 0;   // tilt front-back –180–180 (X axis)
  const gamma = e.gamma || 0;   // tilt left-right –90–90 (Y axis)

  // Calibrate on first reading
  if (_gyroAlpha0 === null) _gyroAlpha0 = alpha;

  // Convert device orientation to sky azimuth / altitude
  // When holding phone up (beta≈90°), we look at zenith; beta=0 is flat
  const azDeg  = ((alpha - _gyroAlpha0 + 360) % 360);
  const altDeg = Math.max(-10, Math.min(90, beta - 45)); // tilt 45° = horizon

  // Smooth with lerp
  _lastGyroAlpha = _lerp(_lastGyroAlpha, azDeg  * DEG, _GYRO_SMOOTH);
  _lastGyroBeta  = _lerp(_lastGyroBeta,  altDeg * DEG, _GYRO_SMOOTH);

  state.azimuth  = _lastGyroAlpha;
  state.altitude = _lastGyroBeta;
}

function _lerp(a, b, t) {
  // Handle angle wrapping for azimuth
  let diff = b - a;
  if (diff >  Math.PI) diff -= Math.PI * 2;
  if (diff < -Math.PI) diff += Math.PI * 2;
  return a + diff * t;
}

function _showGyroHint() {
  let hint = document.getElementById('gyro-hint');
  if (hint) return;
  hint = document.createElement('div');
  hint.id = 'gyro-hint';
  hint.style.cssText = `position:fixed;bottom:80px;left:50%;transform:translateX(-50%);
    z-index:300;background:rgba(0,247,255,.1);border:1px solid rgba(0,247,255,.3);
    border-radius:14px;padding:10px 18px;font-family:var(--orb);font-size:.6rem;
    color:rgba(0,247,255,.8);letter-spacing:.08em;pointer-events:none;
    animation:fadeInUp .4s ease;backdrop-filter:blur(16px);`;
  hint.innerHTML = '📱 Point phone at the sky — stars align with real positions';
  document.body.appendChild(hint);
  setTimeout(() => hint?.remove(), 5000);
}

function _showGyroPrompt(msg) {
  const el = document.createElement('div');
  el.style.cssText = `position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);
    z-index:9000;background:rgba(3,6,20,.96);border:1px solid rgba(255,100,100,.3);
    border-radius:16px;padding:20px 24px;font-size:.82rem;color:rgba(255,200,200,.8);
    max-width:280px;text-align:center;backdrop-filter:blur(20px);`;
  el.innerHTML = `<i class="fas fa-exclamation-triangle" style="font-size:1.4rem;margin-bottom:10px;display:block;color:rgba(255,150,100,.7)"></i>${msg}`;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 4000);
}


/* ══════════════════════════════════════════════════════════
   CAMERA NAVIGATION HELPERS
══════════════════════════════════════════════════════════ */

/* Smooth camera animation to target az/alt */
function animateCameraTo(targetAz, targetAlt, onDone) {
  const startAz  = state.azimuth;
  const startAlt = state.altitude;
  let t = 0;
  const anim = setInterval(() => {
    t += 0.06;
    if (t >= 1) { t = 1; clearInterval(anim); onDone?.(); }
    const ease = t < 0.5 ? 2*t*t : -1+(4-2*t)*t;

    // Handle az wraparound — always take shortest path
    let dAz = targetAz - startAz;
    if (dAz >  Math.PI) dAz -= Math.PI * 2;
    if (dAz < -Math.PI) dAz += Math.PI * 2;

    state.azimuth  = startAz + dAz * ease;
    state.altitude = startAlt + (targetAlt - startAlt) * ease;
  }, 16);
  navigator.vibrate?.(8);
}

/* Face a cardinal direction */
function lookCardinal(azRad, altRad) {
  animateCameraTo(azRad, altRad ?? 0.1);
}

/* Compute sun equatorial position (low-precision, ±1°) */
function sunPosition(date) {
  const JD  = getJD(date || new Date());
  const n   = JD - 2451545.0;              // days since J2000.0
  const L   = (280.460 + 0.9856474 * n) % 360;  // mean longitude
  const g   = ((357.528 + 0.9856003 * n) % 360) * DEG;  // mean anomaly
  const lambda = (L + 1.915 * Math.sin(g) + 0.020 * Math.sin(2*g)) * DEG;
  const eps = 23.439 * DEG;  // obliquity

  const ra  = Math.atan2(Math.cos(eps)*Math.sin(lambda), Math.cos(lambda)) / DEG;
  const dec = Math.asin(Math.sin(eps)*Math.sin(lambda)) / DEG;
  return { ra: (ra + 360) % 360, dec };
}

/* Convert equatorial RA/Dec + LST to local Azimuth/Altitude */
function equToAltAz(ra, dec, lst) {
  const ha  = ((lst - ra + 360) % 360) * DEG;  // hour angle
  const lat = (OBSERVER?.lat ?? 21.31) * DEG;
  const d   = dec * DEG;
  const alt = Math.asin(Math.sin(lat)*Math.sin(d) + Math.cos(lat)*Math.cos(d)*Math.cos(ha));
  const az  = Math.atan2(
    -Math.cos(d)*Math.sin(ha),
    Math.sin(d)*Math.cos(lat) - Math.cos(d)*Math.cos(ha)*Math.sin(lat)
  );
  return { alt, az: (az / DEG + 360) % 360 * DEG };
}

/* Point camera at the Moon */
function lookAtMoon() {
  const md = moonMesh?.userData?.moonData;
  if (!md) { animateCameraTo(Math.PI, 0.25); return; }  // fallback: south/low
  const lst = getLST(getEffectiveDate());
  const { alt, az } = equToAltAz(md.ra, md.dec, lst);
  if (alt < -0.1) {
    // Moon is below horizon
    const el = document.createElement('div');
    el.style.cssText = 'position:fixed;bottom:90px;left:50%;transform:translateX(-50%);z-index:500;background:rgba(3,6,20,.92);border:1px solid rgba(255,248,200,.2);border-radius:12px;padding:9px 18px;font-family:var(--orb);font-size:.62rem;color:rgba(255,248,200,.7);pointer-events:none;backdrop-filter:blur(16px);';
    el.textContent = '☽ Ka Mahina is below the horizon right now';
    document.body.appendChild(el);
    setTimeout(() => el.remove(), 3500);
    return;
  }
  // Convert local az to camera azimuth convention
  // Camera az=0 → north; equToAltAz gives meteorological az (N=0, E=90)
  animateCameraTo(az, alt, () => {
    // After arriving, click the moon
    if (moonMesh?.userData?.moonData) showMoonPanel(moonMesh.userData.moonData);
  });
}

/* Point camera at the Sun (and show solar info) */
function lookAtSun() {
  const now = getEffectiveDate();
  const sp  = sunPosition(now);
  const lst = getLST(now);
  const { alt, az } = equToAltAz(sp.ra, sp.dec, lst);

  if (alt < -0.05) {
    // Sun below horizon — show sunrise direction
    const sunriseAz = Math.acos(
      -Math.sin(sp.dec * DEG) / Math.cos((OBSERVER?.lat ?? 21.31) * DEG)
    );
    const dir = isNaN(sunriseAz) ? Math.PI*0.5 : sunriseAz;
    animateCameraTo(dir, 0.05);
    const el = document.createElement('div');
    el.style.cssText = 'position:fixed;bottom:90px;left:50%;transform:translateX(-50%);z-index:500;background:rgba(3,6,20,.92);border:1px solid rgba(255,200,80,.2);border-radius:12px;padding:9px 18px;font-family:var(--orb);font-size:.62rem;color:rgba(255,220,100,.75);pointer-events:none;backdrop-filter:blur(16px);';
    el.textContent = '☀ Ka Lā is below the horizon — pointing to sunrise direction';
    document.body.appendChild(el);
    setTimeout(() => el.remove(), 3500);
  } else {
    animateCameraTo(az, alt);
    // Show brief solar info toast
    const el = document.createElement('div');
    el.style.cssText = 'position:fixed;bottom:90px;left:50%;transform:translateX(-50%);z-index:500;background:rgba(3,6,20,.92);border:1px solid rgba(255,200,80,.3);border-radius:12px;padding:9px 18px;font-family:var(--orb);font-size:.62rem;color:rgba(255,220,100,.85);pointer-events:none;backdrop-filter:blur(16px);';
    el.textContent = `☀ Ka Lā — ${Math.round(alt/DEG)}° above horizon`;
    document.body.appendChild(el);
    setTimeout(() => el.remove(), 3000);
  }
  navigator.vibrate?.(8);
}


async function initScene() {
  const fill = document.getElementById('loader-fill');
  const setProgress = p => { if(fill) fill.style.width=p+'%'; };

  /* Cache DOM refs */
  _cacheDOM();
  /* Request live location */
  initGeolocation();
  /* Merge rich star data */
  mergeStarData();
  setProgress(10);

  /* Load and process ʻIwa bird for compass center */
  processIwaForCursor(null, dataUrl => {
    if (!dataUrl) return;
    const img = new Image();
    img.onload = () => { _iwaForCompass = img; };
    img.src = dataUrl;
    /* Set as cursor */
    const cursorEl = document.getElementById('cursor');
    if (cursorEl) {
      cursorEl.innerHTML = `<img src="${dataUrl}" alt="ʻIwa" draggable="false">`;
    }
  });
  setProgress(18);

  /* Load and process Hawaiian star compass PNG */
  processCompassImage(null, img => {
    /* Image loaded — compass will draw on next animate frame */
  });
  setProgress(25);

  _moonUpdateEvery  = _isMobile ? 120 : 90;
  _planetUpdateEvery = _isMobile ? 60  : 30;
  buildPlanets();
  buildMilkyWay();
  setProgress(40);
  buildStarField();
  setProgress(55);
  buildMoon();
  setProgress(65);
  buildHorizon();
  buildZenithMarker();
  buildHorizonGlow();
  setProgress(73);
  buildAltAzGrid();
  setProgress(82);
  buildConstellationLines('hawaiian');
  buildStarLabels('hawaiian');
  buildFormationLabels('hawaiian');
  buildImportanceSprites();
  setProgress(95);

  /* Initial camera position — facing south, slightly up */
  state.azimuth  = Math.PI;
  state.altitude = 0.35;
  updateCamera();
  updateTimeDisplay(0);

  animate();
  setProgress(100);
  setTimeout(_scheduleShootingStar, 4000); // first shooting star after 4s

  setTimeout(()=>{
    const loader=document.getElementById('loader');
    if(loader) loader.classList.add('fade');
    setTimeout(()=>loader?.remove(), 700);
    /* Show how-to on first visit, else show seasonal banner */
    if (!localStorage.getItem('ike-howto-seen')) {
      setTimeout(openHowTo, 1200);
    } else {
      // Auto-check current season
      setTimeout(() => {
        const now = new Date();
        const month = now.getMonth() + 1;
        const event = SEASONAL_EVENTS.find(e => e.month === month);
        if (event) {
          document.getElementById('seasonal-badge-text').textContent = event.name;
          document.getElementById('seasonal-badge').classList.add('show');
          setTimeout(() => document.getElementById('seasonal-badge').classList.remove('show'), 6000);
        }
      }, 2000);
    }
  }, 600);
}

// Start
initScene();